solution_code:
#include <iostream>
#include <iomanip>

class Celsius {
    float m_degrees;
public:
    Celsius(float d) : m_degrees{d} {}
    explicit operator float() const { return m_degrees; }
};

int main() {
    float input;
    std::cin >> input;
    Celsius temp{input};
    float val = static_cast<float>(temp);
    std::cout << "Temp: " << std::fixed << std::setprecision(1) << val << '\n';
    return 0;
}

