solution_code:
#include <iostream>
#include <iomanip>

class Fraction {
    int m_num;
    int m_den;
public:
    Fraction(int num, int den) : m_num{num}, m_den{den} {}

    operator double() const {
        return static_cast<double>(m_num) / m_den;
    }
};

int main() {
    int n, d;
    std::cin >> n >> d;
    Fraction f{n, d};
    double val = f;
    std::cout << "Value: " << std::fixed << std::setprecision(4) << val << '\n';
    return 0;
}
